// n8n Code node (Run once for each item) or (Run once for all items)
// This version works for either mode because it maps over $input.all().

const items = $input.all();

// Matches: <!-- #varname 'quoted value' -->
// - varname: [A-Za-z_][A-Za-z0-9_]*
// - value: single-quoted, supports escaped \' inside
const directiveRegex =
  /<!--\s*#([A-Za-z_][A-Za-z0-9_]*)\s*'((?:\\'|[^'])*)'\s*-->/g;

function unescapeSingleQuoted(s) {
  // handle \' and \\ (basic but practical)
  return s.replace(/\\'/g, "'").replace(/\\\\/g, "\\");
}

return items.map((item) => {
  const json = { ...item.json };

  const html = typeof json.html === "string" ? json.html : "";
  if (!html) return item; // nothing to do

  const extracted = {};
  const cleanedHtml = html.replace(directiveRegex, (full, varName, rawValue) => {
    extracted[varName] = unescapeSingleQuoted(rawValue);
    return ""; // remove directive comment
  });

  // Optionally trim the resulting HTML (keeps output tidy)
  json.html = cleanedHtml.trim();

  // Merge extracted vars onto payload (extracted takes precedence)
  Object.assign(json, extracted);

  return { ...item, json };
});

